  1	import * as React from 'react';
  2	import { BootstrapSlider } from './BootstrapSlider';
  3	import { Button, ButtonVariant, InputGroupText, TextInput, Tooltip, TooltipPosition } from '@patternfly/react-core';
  4	import { Boundaries } from './Boundaries';
  5	import { kialiStyle } from 'styles/StyleUtils';
  6	import { MinusIcon, PlusIcon, ThumbTackIcon, MigrationIcon } from '@patternfly/react-icons';
  7	
  8	export const noop = Function.prototype;
  9	
 10	type SliderProps = {
 11	  id: string;
 12	  input: boolean;
 13	  inputFormat: string;
 14	  locked: boolean;
 15	  max: number;
 16	  maxLimit: number;
 17	  min: number;
 18	  mirrored: boolean;
 19	  onLock: (locked: boolean) => void;
 20	  onMirror: (mirror: boolean) => void;
 21	  onSlide: (value: number) => void;
 22	  onSlideStop: (value: number) => void;
 23	  orientation: string;
 24	  showLock: boolean;
 25	  showMirror: boolean;
 26	  sliderClass: string;
 27	  step: number;
 28	  ticks: number[];
 29	  ticks_labels: string[];
 30	  tooltip: boolean;
 31	  tooltipFormatter: (value: number) => string;
 32	  value: number;
 33	};
 34	
 35	type SliderState = {
 36	  tooltipFormat: string;
 37	  value: number;
 38	};
 39	
 40	export class Slider extends React.Component<SliderProps, SliderState> {
 41	  static defaultProps = {
 42	    id: null,
 43	    orientation: 'horizontal',
 44	    min: 0,
 45	    max: 100,
 46	    maxLimit: 100,
 47	    value: 0,
 48	    step: 1,
 49	    ticks: [],
 50	    ticks_labels: [],
 51	    toolTip: false,
 52	    tooltipFormatter: noop,
 53	    onSlide: noop,
 54	    onSlideStop: noop,
 55	    label: null,
 56	    labelClass: null,
 57	    input: false,
 58	    sliderClass: null,
 59	    inputFormat: '',
 60	    locked: false,
 61	    showLock: true,
 62	    onLock: noop,
 63	    showMirror: true,
 64	    onMirror: noop
 65	  };
 66	
 67	  constructor(props: SliderProps) {
 68	    super(props);
 69	
 70	    this.state = {
 71	      value: this.props.value,
 72	      tooltipFormat: this.props.inputFormat
 73	    };
 74	  }
 75	
 76	  componentDidMount(): void {
 77	    // This empty setState forces a re-render which resolves an issue with initial tick_label placement
 78	    this.setState({});
 79	  }
 80	
 81	  componentDidUpdate(prevProps: Readonly<SliderProps>): void {
 82	    if (prevProps.value !== this.props.value || this.state.value !== this.props.value) {
 83	      this.setState({ value: this.props.value });
 84	    }
 85	  }
 86	
 87	  onSlide = (value: number): void => {
 88	    this.setState({ value }, () => this.props.onSlide(value));
 89	  };
 90	
 91	  onSlideStop = (value: number): void => {
 92	    this.setState({ value }, () => this.props.onSlideStop(value));
 93	  };
 94	
 95	  onPlus = (): void => {
 96	    const newValue = Number(this.state.value || 0);
 97	    this.updateNewValue(newValue + 1);
 98	  };
 99	
100	  onMinus = (): void => {
101	    const newValue = Number(this.state.value || 0);
102	    this.updateNewValue(newValue - 1);
103	  };
104	
105	  onInputChange = (value: string | number): void => {
106	    const newValue = Number(value);
107	    this.updateNewValue(Number.isNaN(newValue) ? 0 : newValue);
108	  };
109	
110	  updateNewValue = (newValue: number): void => {
111	    if (newValue > this.props.max) {
112	      newValue = this.props.max;
113	    }
114	
115	    if (newValue < 0) {
116	      newValue = 0;
117	    }
118	
119	    this.setState({ value: newValue }, () => this.props.onSlide(newValue));
120	  };
121	
122	  onFormatChange = (format: string): void => {
123	    this.setState({ tooltipFormat: format });
124	  };
125	
126	  formatter = (value: number): string => {
127	    return this.props.tooltipFormatter !== noop
128	      ? this.props.tooltipFormatter(value)
129	      : `${value} ${this.state.tooltipFormat} ${this.props.mirrored ? ' mirrored traffic' : ''}`;
130	  };
131	
132	  render(): React.ReactNode {
133	    const BSSlider = (
134	      <BootstrapSlider
135	        {...this.props}
136	        formatter={this.formatter}
137	        value={this.state.value}
138	        onSlide={this.onSlide}
139	        onSlideStop={this.onSlideStop}
140	      />
141	    );
142	
143	    const leftButtonStyle = kialiStyle({
144	      width: '20px',
145	      paddingLeft: 0,
146	      paddingRight: 0,
147	      marginLeft: 0,
148	      marginRight: '5px'
149	    });
150	
151	    const inputStyle = kialiStyle({
152	      width: '3rem',
153	      textAlign: 'center',
154	      marginLeft: 0,
155	      marginRight: 0
156	    });
157	
158	    const rightButtonStyle = kialiStyle({
159	      width: '20px',
160	      paddingLeft: 0,
161	      paddingRight: 0,
162	      marginLeft: '5px',
163	      marginRight: '5px'
164	    });
165	
166	    const pinButtonStyle = kialiStyle({
167	      paddingLeft: '8px',
168	      paddingRight: '8px'
169	    });
170	
171	    const LockIcon = (
172	      <Tooltip
173	        position={TooltipPosition.top}
174	        content={<>{this.props.locked ? 'Unlock' : 'Lock'} Weight for this Workload</>}
175	      >
176	        <Button
177	          className={pinButtonStyle}
178	          isDisabled={this.props.mirrored}
179	          variant={this.props.locked ? ButtonVariant.primary : ButtonVariant.secondary}
180	          onClick={() => this.props.onLock(!this.props.locked)}
181	        >
182	          <ThumbTackIcon />
183	        </Button>
184	      </Tooltip>
185	    );
186	
187	    const MirrorIcon = (
188	      <Tooltip position={TooltipPosition.top} content={<>Mirror % traffic to this Workload</>}>
189	        <Button
190	          className={pinButtonStyle}
191	          variant={this.props.mirrored ? ButtonVariant.primary : ButtonVariant.secondary}
192	          onClick={() => this.props.onMirror(!this.props.mirrored)}
193	          style={{ marginLeft: '10px', marginRight: '10px' }}
194	        >
195	          <MigrationIcon />
196	        </Button>
197	      </Tooltip>
198	    );
199	
200	    return (
201	      <>
202	        <Boundaries slider={BSSlider} {...this.props}>
203	          {this.props.input && (
204	            <>
205	              <Button
206	                className={leftButtonStyle}
207	                variant={ButtonVariant.link}
208	                isDisabled={this.props.locked}
209	                onClick={() => this.onMinus()}
210	              >
211	                <MinusIcon />
212	              </Button>
213	              <TextInput
214	                className={inputStyle}
215	                id="slider-text"
216	                aria-label="slider-text"
217	                value={this.state.value}
218	                onChange={(_event, value: string | number) => this.onInputChange(value)}
219	                isDisabled={this.props.locked}
220	                data-test={`input-${this.props.id}`}
221	              />
222	              <Button
223	                className={rightButtonStyle}
224	                variant={ButtonVariant.link}
225	                isDisabled={this.props.locked}
226	                onClick={() => this.onPlus()}
227	              >
228	                <PlusIcon />
229	              </Button>
230	              <InputGroupText>{this.props.inputFormat}</InputGroupText>
231	            </>
232	          )}
233	
234	          {this.props.showMirror ? MirrorIcon : <></>}
235	
236	          {this.props.showLock ? LockIcon : <></>}
237	        </Boundaries>
238	      </>
239	    );
240	  }
241	}

